        catch (Exception ex)
        {
            ShowToast($"Failed to revoke session: {ex.Message}", isError: true);
        }
        finally
        {
            _revoking = false;
            _showRevokeDialog = false;
            _sessionToRevoke = null;
        }
    }

    // --- Appearance ---

    private async Task SaveAppearance()
