    transition: all 0.2s ease;
}

.preview-light {
    background: #ffffff;
    color: #212529;
}

.preview-dark {
    background: #212529;
    color: #f8f9fa;
    border-color: #495057;
}

.preview-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.5rem;
}

.preview-body {
    font-size: inherit;
    line-height: 1.5;
}

.preview-actions {
    display: flex;
}
"}

toolArgs.file_text:
@page "/settings"
@rendermode InteractiveServer
@using sv_ea71d0410b0d492297a94499c8e2eff5.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <nav class="settings-sidebar">
        <h5 class="sidebar-title">Settings</h5>
        <ul class="nav flex-column">
            @foreach (var section in _sections)
            {
                <li class="nav-item">
                    <button class="nav-link @(section == _activeSection ? "active" : "")"
                            @onclick="() => SetActiveSection(section)">
                        <span class="section-icon">@GetSectionIcon(section)</span>
                        @section
                    </button>
                </li>
            }
        </ul>
    </nav>

    <div class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center p-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else
        {
            @if (_activeSection == "Profile")
            {
                @RenderProfileSection()
            }
            else if (_activeSection == "Notifications")
            {
                @RenderNotificationsSection()
            }
            else if (_activeSection == "Security")
            {
                @RenderSecuritySection()
            }
            else if (_activeSection == "Appearance")
            {
                @RenderAppearanceSection()
            }
        }
    </div>
</div>

@* Toast notification *@
@if (_toastVisible)
{
    <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
        <span>@_toastMessage</span>
        <button class="btn-close btn-close-white ms-2" @onclick="() => _toastVisible = false"></button>
    </div>
}

@* Session revoke confirmation dialog *@
@if (_showRevokeDialog)
{
    <div class="modal-backdrop show"></div>
    <div class="modal d-block" tabindex="-1">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong> from <strong>@_sessionToRevoke?.Location</strong>?</p>
                    <p class="text-muted mb-0">This will sign out that device immediately.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_revoking">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Revoke Session
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";
    private bool _loading = true;

    // Toast state
    private bool _toastVisible;
    private string _toastMessage = "";
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // Profile state
    private UserProfile? _savedProfile;
    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _savingProfile;

    // Notification state
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = ["general", "announcements", "engineering", "design", "marketing", "support", "random"];
    private HashSet<string> _mutedChannels = new();
    private bool _savingNotifications;

    // Security state
    private SecuritySettings? _securitySettings;
    private bool _changePasswordExpanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private bool _showRevokeDialog;
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;

    // Appearance state
    private string _theme = "System";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private bool _savingAppearance;

    private readonly string[] _availableLanguages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese", "Korean", "Portuguese"];

    protected override async Task OnInitializedAsync()
    {
        await LoadSectionData("Profile");
    }

    private async Task SetActiveSection(string section)
    {
        if (_activeSection == section) return;
        _activeSection = section;
        _loading = true;
        await LoadSectionData(section);
    }

    private async Task LoadSectionData(string section)
    {
        try
        {
            switch (section)
            {
                case "Profile":
                    var profile = await SettingsService.GetProfileAsync();
                    _savedProfile = profile;
                    _displayName = profile.DisplayName;
                    _email = profile.Email;
                    _avatarUrl = profile.AvatarUrl;
                    _bio = profile.Bio;
                    break;

                case "Notifications":
                    var prefs = await SettingsService.GetNotificationPrefsAsync();
                    _emailNotifications = prefs.EmailNotifications;
                    _pushNotifications = prefs.PushNotifications;
                    _weeklyDigest = prefs.WeeklyDigest;
                    _mutedChannels = new HashSet<string>(prefs.MutedChannels);
                    break;

                case "Security":
                    _securitySettings = await SettingsService.GetSecuritySettingsAsync();
                    _changePasswordExpanded = false;
                    _currentPassword = "";
                    _newPassword = "";
                    _confirmPassword = "";
                    break;

                case "Appearance":
                    var appearance = await SettingsService.GetAppearanceAsync();
                    _theme = appearance.Theme;
                    _fontSize = appearance.FontSize;
                    _language = appearance.Language;
                    _compactMode = appearance.CompactMode;
                    break;
            }
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to load {section.ToLower()} settings: {ex.Message}", isError: true);
        }
        finally
        {
            _loading = false;
        }
    }

    // --- Profile ---

    private async Task SaveProfile()
    {
        _savingProfile = true;
        try
        {
            var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(profile);
            _savedProfile = profile;
            ShowToast("Profile saved successfully.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save profile: {ex.Message}", isError: true);
        }
        finally
        {
            _savingProfile = false;
        }
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            _displayName = _savedProfile.DisplayName;
            _email = _savedProfile.Email;
            _avatarUrl = _savedProfile.AvatarUrl;
            _bio = _savedProfile.Bio;
        }
    }

    private bool ProfileHasChanges =>
        _savedProfile is not null &&
        (_displayName != _savedProfile.DisplayName ||
         _email != _savedProfile.Email ||
         _avatarUrl != _savedProfile.AvatarUrl ||
         _bio != _savedProfile.Bio);

    // --- Notifications ---

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotificationPrefs()
    {
        _savingNotifications = true;
        try
        {
            var prefs = new NotificationPrefs(
                _emailNotifications, _pushNotifications, _weeklyDigest,
                _mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            ShowToast("Notification preferences saved.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save preferences: {ex.Message}", isError: true);
        }
        finally
        {
            _savingNotifications = false;
        }
    }

    // --- Security ---

    private async Task ChangePassword()
    {
        if (_newPassword != _confirmPassword)
        {
            ShowToast("New password and confirmation do not match.", isError: true);
            return;
        }

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            ShowToast("Please fill in all password fields.", isError: true);
            return;
        }

        _changingPassword = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _changePasswordExpanded = false;
            ShowToast("Password updated successfully.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to change password: {ex.Message}", isError: true);
        }
        finally
        {
            _changingPassword = false;
        }
    }

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeDialog = true;
    }

    private void CancelRevoke()
    {
        _showRevokeDialog = false;
        _sessionToRevoke = null;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;
        _revoking = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _securitySettings = await SettingsService.GetSecuritySettingsAsync();
            ShowToast("Session revoked.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to revoke session: {ex.Message}", isError: true);
        }
        finally
        {
            _revoking = false;
            _showRevokeDialog = false;
            _sessionToRevoke = null;
        }
    }

    // --- Appearance ---

    private async Task SaveAppearance()
    {
        _savingAppearance = true;
        try
        {
            var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            ShowToast("Appearance settings saved.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save appearance: {ex.Message}", isError: true);
        }
        finally
        {
            _savingAppearance = false;
        }
    }

    // --- Toast ---

    private async void ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastIsError = isError;
        _toastVisible = true;
        StateHasChanged();

        try
        {
            await Task.Delay(4000, token);
            _toastVisible = false;
            StateHasChanged();
        }
        catch (TaskCanceledException)
        {
            // Another toast replaced this one
        }
    }

    private static string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };

    private string GetPreviewFontSize() => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    // --- Render fragments ---

    private RenderFragment RenderProfileSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Profile</h3>
            <p class="text-muted">Manage your personal information and public profile.</p>
            <hr />

            <div class="row">
                <div class="col-md-8">
                    <div class="mb-3">
                        <label class="form-label" for="displayName">Display Name</label>
                        <input id="displayName" type="text" class="form-control" @bind="_displayName" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label" for="email">Email</label>
                        <input id="email" type="email" class="form-control" @bind="_email" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label" for="bio">Bio</label>
                        <textarea id="bio" class="form-control" rows="4" @bind="_bio"></textarea>
                    </div>
                </div>
                <div class="col-md-4">
                    <div class="avatar-preview-area">
                        <label class="form-label">Avatar Preview</label>
                        <div class="avatar-frame">
                            @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                            {
                                <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                            }
                            else
                            {
                                <div class="avatar-placeholder">👤</div>
                            }
                        </div>
                        <div class="mt-2">
                            <label class="form-label small text-muted" for="avatarUrl">Avatar URL</label>
                            <input id="avatarUrl" type="url" class="form-control form-control-sm" @bind="_avatarUrl" placeholder="https://example.com/avatar.png" />
                        </div>
                    </div>
                </div>
            </div>

            <div class="d-flex gap-2 mt-3">
                <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_savingProfile">
                    @if (_savingProfile)
                    {
                        <span class="spinner-border spinner-border-sm me-1"></span>
                    }
                    Save Changes
                </button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges" disabled="@(!ProfileHasChanges)">
                    Discard Changes
                </button>
            </div>
        </section>
    };

    private RenderFragment RenderNotificationsSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Notifications</h3>
            <p class="text-muted">Control how and when you receive notifications.</p>
            <hr />

            <div class="mb-4">
                <h5>General</h5>
                <div class="form-check form-switch mb-2">
                    <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                    <label class="form-check-label" for="emailNotif">Email Notifications</label>
                </div>
                <div class="form-check form-switch mb-2">
                    <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                    <label class="form-check-label" for="pushNotif">Push Notifications</label>
                </div>
                <div class="form-check form-switch mb-2">
                    <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                    <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
                </div>
            </div>

            <div class="mb-4">
                <h5>Muted Channels</h5>
                <p class="text-muted small">Muted channels will not send you any notifications.</p>
                @foreach (var channel in _allChannels)
                {
                    var ch = channel;
                    <div class="form-check mb-1">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{ch}")"
                               checked="@_mutedChannels.Contains(ch)"
                               @onchange="e => ToggleMutedChannel(ch, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{ch}")">
                            <span class="badge bg-secondary me-1">#</span>@ch
                        </label>
                    </div>
                }
            </div>

            <button class="btn btn-primary" @onclick="SaveNotificationPrefs" disabled="@_savingNotifications">
                @if (_savingNotifications)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Preferences
            </button>
        </section>
    };

    private RenderFragment RenderSecuritySection() => __builder =>
    {
        <section class="settings-section">
            <h3>Security</h3>
            <p class="text-muted">Manage your password, two-factor authentication, and active sessions.</p>
            <hr />

            @* Change Password *@
            <div class="card mb-4">
                <div class="card-header d-flex justify-content-between align-items-center"
                     style="cursor: pointer;"
                     @onclick="() => _changePasswordExpanded = !_changePasswordExpanded">
                    <span>🔑 Change Password</span>
                    <span class="expand-icon">@(_changePasswordExpanded ? "▲" : "▼")</span>
                </div>
                @if (_changePasswordExpanded)
                {
                    <div class="card-body">
                        <div class="mb-3">
                            <label class="form-label" for="currentPwd">Current Password</label>
                            <input id="currentPwd" type="password" class="form-control" @bind="_currentPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label" for="newPwd">New Password</label>
                            <input id="newPwd" type="password" class="form-control" @bind="_newPassword" />
                        </div>
                        <div class="mb-3">
                            <label class="form-label" for="confirmPwd">Confirm New Password</label>
                            <input id="confirmPwd" type="password" class="form-control" @bind="_confirmPassword" />
                        </div>
                        @if (_securitySettings?.LastPasswordChange is not null)
                        {
                            <p class="text-muted small">Last changed: @_securitySettings.LastPasswordChange.Value.ToString("MMMM d, yyyy")</p>
                        }
                        <button class="btn btn-primary" @onclick="ChangePassword" disabled="@_changingPassword">
                            @if (_changingPassword)
                            {
                                <span class="spinner-border spinner-border-sm me-1"></span>
                            }
                            Update Password
                        </button>
                    </div>
                }
            </div>

            @* Two-Factor Authentication *@
            <div class="card mb-4">
                <div class="card-body d-flex justify-content-between align-items-center">
                    <div>
                        <h6 class="mb-1">🛡️ Two-Factor Authentication</h6>
                        <span class="badge @(_securitySettings?.TwoFactorEnabled == true ? "bg-success" : "bg-warning text-dark")">
                            @(_securitySettings?.TwoFactorEnabled == true ? "Enabled" : "Disabled")
                        </span>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="twoFactor"
                               checked="@(_securitySettings?.TwoFactorEnabled ?? false)" disabled />
                    </div>
                </div>
            </div>

            @* Active Sessions *@
            <div class="mb-4">
                <h5>Active Sessions</h5>
                @if (_securitySettings?.Sessions is { Count: > 0 })
                {
                    <div class="table-responsive">
                        <table class="table table-hover align-middle">
                            <thead>
                                <tr>
                                    <th>Device</th>
                                    <th>Location</th>
                                    <th>Last Active</th>
                                    <th></th>
                                </tr>
                            </thead>
                            <tbody>
                                @foreach (var session in _securitySettings.Sessions)
                                {
                                    var isFirst = session == _securitySettings.Sessions[0];
                                    <tr>
                                        <td>
                                            @session.Device
                                            @if (isFirst)
                                            {
                                                <span class="badge bg-primary ms-1">Current</span>
                                            }
                                        </td>
                                        <td>@session.Location</td>
                                        <td>@session.LastActive.ToString("MMM d, yyyy h:mm tt")</td>
                                        <td>
                                            @if (!isFirst)
                                            {
                                                <button class="btn btn-outline-danger btn-sm" @onclick="() => RequestRevoke(session)">
                                                    Revoke
                                                </button>
                                            }
                                        </td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    </div>
                }
                else
                {
                    <p class="text-muted">No active sessions found.</p>
                }
            </div>
        </section>
    };

    private RenderFragment RenderAppearanceSection() => __builder =>
    {
        <section class="settings-section">
            <h3>Appearance</h3>
            <p class="text-muted">Customize how the application looks and feels.</p>
            <hr />

            <div class="row">
                <div class="col-md-6">
                    @* Theme *@
                    <div class="mb-4">
                        <h5>Theme</h5>
                        @foreach (var t in new[] { "Light", "Dark", "System" })
                        {
                            var theme = t;
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme}")"
                                       checked="@(_theme == theme)"
                                       @onchange="() => _theme = theme" />
                                <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                            </div>
                        }
                    </div>

                    @* Font Size *@
                    <div class="mb-4">
                        <h5>Font Size</h5>
                        @foreach (var fs in new[] { "Small", "Medium", "Large" })
                        {
                            var size = fs;
                            <div class="form-check">
                                <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{size}")"
                                       checked="@(_fontSize == size)"
                                       @onchange="() => _fontSize = size" />
                                <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                            </div>
                        }
                    </div>

                    @* Language *@
                    <div class="mb-4">
                        <h5>Language</h5>
                        <select class="form-select" @bind="_language">
                            @foreach (var lang in _availableLanguages)
                            {
                                <option value="@lang">@lang</option>
                            }
                        </select>
                    </div>

                    @* Compact Mode *@
                    <div class="mb-4">
                        <div class="form-check form-switch">
                            <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                            <label class="form-check-label" for="compactMode">Compact Mode</label>
                        </div>
                        <small class="text-muted">Reduces spacing and padding throughout the interface.</small>
                    </div>
                </div>

                <div class="col-md-6">
                    @* Live Preview *@
                    <div class="mb-4">
                        <h5>Preview</h5>
                        <div class="appearance-preview @(_theme == "Dark" ? "preview-dark" : "preview-light")"
                             style="font-size: @GetPreviewFontSize(); @(_compactMode ? "padding: 0.75rem;" : "padding: 1.5rem;")">
                            <div class="preview-header">
                                <strong>Sample Card</strong>
                                <span class="badge @(_theme == "Dark" ? "bg-light text-dark" : "bg-dark")">@_theme</span>
                            </div>
                            <p class="preview-body" style="@(_compactMode ? "margin: 0.25rem 0;" : "margin: 0.75rem 0;")">
                                This is a preview of your selected appearance settings.
                                Font size: <strong>@_fontSize</strong>. Language: <strong>@_language</strong>.
                            </p>
                            <div class="preview-actions" style="@(_compactMode ? "gap: 0.25rem;" : "gap: 0.5rem;")">
                                <span class="btn btn-sm @(_theme == "Dark" ? "btn-outline-light" : "btn-outline-dark")">Action</span>
                                <span class="btn btn-sm @(_theme == "Dark" ? "btn-light" : "btn-dark")">Primary</span>
                            </div>
                        </div>
                    </div>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_savingAppearance">
                @if (_savingAppearance)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </section>
    };
}

